# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

from flask import Flask, request, jsonify
from collections import Counter
import numpy as np
import pickle
from sklearn.ensemble import RandomForestClassifier
from sklearn.preprocessing import LabelEncoder
import os

app = Flask(__name__)

# In-memory storage for labels and model
labels_storage = {}
model = None
label_encoder = LabelEncoder()

@app.route('/label', methods=['POST'])
def add_label():
    data = request.get_json()
    image_id = data['image_id']
    annotator_id = data['annotator_id']
    label = data['label']
    
    if image_id not in labels_storage:
        labels_storage[image_id] = {}
    
    if annotator_id not in labels_storage[image_id]:
        labels_storage[image_id][annotator_id] = []
    
    labels_storage[image_id][annotator_id].append(label)
    
    return jsonify({"status": "success"})

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated = {}
    for image_id, annotators in labels_storage.items():
        all_labels = []
        for labels in annotators.values():
            all_labels.extend(labels)
        
        if all_labels:
            most_common = Counter(all_labels).most_common(1)
            aggregated[image_id] = most_common[0][0] if most_common else None
    
    return jsonify(aggregated)

@app.route('/train', methods=['POST'])
def train_model():
    global model, label_encoder
    
    # Get all aggregated labels
    aggregated_labels = {}
    for image_id, annotators in labels_storage.items():
        all_labels = []
        for labels in annotators.values():
            all_labels.extend(labels)
        
        if all_labels:
            most_common = Counter(all_labels).most_common(1)
            aggregated_labels[image_id] = most_common[0][0] if most_common else None
    
    # For demo purposes, we'll use dummy features
    # In practice, you'd extract features from images
    X = np.random.rand(len(aggregated_labels), 10)  # 10 features
    y = list(aggregated_labels.values())
    
    # Encode labels
    y_encoded = label_encoder.fit_transform(y)
    
    # Train model
    model = RandomForestClassifier(n_estimators=100, random_state=42)
    model.fit(X, y_encoded)
    
    return jsonify({"status": "model trained"})

@app.route('/predict', methods=['POST'])
def predict():
    global model
    
    if model is None:
        return jsonify({"error": "Model not trained"}), 400
    
    data = request.get_json()
    features = np.array(data['features']).reshape(1, -1)
    
    prediction = model.predict(features)
    predicted_label = label_encoder.inverse_transform(prediction)[0]
    
    return jsonify({"prediction": predicted_label})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)